    // 执行时直接返回 true，表示这个伪文件支持 read。
    fn readable(&self) -> bool {
        true
    }
    // /proc/<pid>/stat 不允许写。
    // 执行时直接返回 false，表示这个伪文件是只读的。
    fn writable(&self) -> bool {
        false
    }
